import xml.etree.ElementTree as ET

def validate_xml(xml_file):
    tree = ET.parse(xml_file)
    root = tree.getroot()
    
    # Validate the XML document by checking for required elements and attributes
    if not root.find('./name'):
        raise ValueError("Missing 'name' element")
    if not root.find('./age'):
        raise ValueError("Missing 'age' element")
    if not root.attrib['gender'] in ['male', 'female']:
        raise ValueError("Invalid gender value")
    
    # Validate the XML document by checking for invalid characters in the text nodes
    for node in tree.iter():
        if node.text and not node.text.isprintable():
            raise ValueError("Invalid character in text node")
            
    return True